UPDATE im_conversation_read
SET last_read_seq = #{newSeq},
version = version + 1,
update_time = #{updateTime}
WHERE user_id = #{userId}
AND conversation_type = #{conversationType}
AND conversation_id = #{conversationId}
AND last_read_seq  <  #{newSeq}

